import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Modules and Imports","description":"","frontmatter":{},"headers":[],"relativePath":"guide/modules.md","filePath":"guide/modules.md"}'),o={name:"guide/modules.md"};function p(i,a,l,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="modules-and-imports" tabindex="-1">Modules and Imports <a class="header-anchor" href="#modules-and-imports" aria-label="Permalink to &quot;Modules and Imports&quot;">​</a></h1><p>Vex uses a modern <code>import</code>/<code>export</code> system inspired by Go and JavaScript, ensuring clear module boundaries and explicit dependency management.</p><h2 id="import-syntax" tabindex="-1">Import Syntax <a class="header-anchor" href="#import-syntax" aria-label="Permalink to &quot;Import Syntax&quot;">​</a></h2><h3 id="namespace-import" tabindex="-1">Namespace Import <a class="header-anchor" href="#namespace-import" aria-label="Permalink to &quot;Namespace Import&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import * as io from &quot;io&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    io.println(&quot;Hello, World!&quot;)</span></span>
<span class="line"><span>    return 0</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="named-imports" tabindex="-1">Named Imports <a class="header-anchor" href="#named-imports" aria-label="Permalink to &quot;Named Imports&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import { sqrt, PI } from &quot;math&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main() {</span></span>
<span class="line"><span>    let result = sqrt(16.0)</span></span>
<span class="line"><span>    println(f&quot;PI is {PI}&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="export-syntax" tabindex="-1">Export Syntax <a class="header-anchor" href="#export-syntax" aria-label="Permalink to &quot;Export Syntax&quot;">​</a></h2><p>Everything in a module is <strong>private</strong> by default. Use the <code>export</code> keyword to expose items to other modules.</p><h3 id="exporting-functions-and-structs" tabindex="-1">Exporting Functions and Structs <a class="header-anchor" href="#exporting-functions-and-structs" aria-label="Permalink to &quot;Exporting Functions and Structs&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Public function</span></span>
<span class="line"><span>export fn calculate(x: i32): i32 {</span></span>
<span class="line"><span>    return x * 2</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Public struct</span></span>
<span class="line"><span>export struct User {</span></span>
<span class="line"><span>    public:</span></span>
<span class="line"><span>    name: string</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Private helper (not visible outside)</span></span>
<span class="line"><span>fn internal_aid() { }</span></span></code></pre></div><h3 id="exporting-methods" tabindex="-1">Exporting Methods <a class="header-anchor" href="#exporting-methods" aria-label="Permalink to &quot;Exporting Methods&quot;">​</a></h3><p>Methods associated with an exported struct are also typically exported:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export struct Counter {</span></span>
<span class="line"><span>    public:</span></span>
<span class="line"><span>    count: i64</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export fn (self: &amp;Counter!) increment() {</span></span>
<span class="line"><span>    self.count += 1</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="file-based-modules" tabindex="-1">File-Based Modules <a class="header-anchor" href="#file-based-modules" aria-label="Permalink to &quot;File-Based Modules&quot;">​</a></h2><p>Each <code>.vx</code> file is automatically treated as a module. The file path relative to the project root or standard library determines the import path.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── main.vx          # Root module</span></span>
<span class="line"><span>└── utils.vx         # imported as &quot;./utils&quot;</span></span></code></pre></div><h2 id="re-exporting" tabindex="-1">Re-exporting <a class="header-anchor" href="#re-exporting" aria-label="Permalink to &quot;Re-exporting&quot;">​</a></h2><p>Modules can act as a gateway by re-exporting items from other modules:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// models/mod.vx</span></span>
<span class="line"><span>export { User } from &quot;./user&quot;</span></span>
<span class="line"><span>export { Post } from &quot;./post&quot;</span></span></code></pre></div><h2 id="comparison-with-other-languages" tabindex="-1">Comparison with Other Languages <a class="header-anchor" href="#comparison-with-other-languages" aria-label="Permalink to &quot;Comparison with Other Languages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Vex</th><th>Rust</th><th>Go</th></tr></thead><tbody><tr><td>Import</td><td><code>import { x } from &quot;m&quot;</code></td><td><code>use m.x</code></td><td><code>import &quot;m&quot;</code></td></tr><tr><td>Export</td><td><code>export fn f()</code></td><td><code>pub fn f()</code></td><td><code>func F()</code></td></tr><tr><td>Namespace</td><td><code>import * as m</code></td><td><code>use m</code></td><td><code>import m &quot;m&quot;</code></td></tr></tbody></table><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Export sparingly</strong>: Keep your module&#39;s internal implementation details private.</li><li><strong>Prefer named imports</strong>: It makes dependencies explicit and easier to track.</li><li><strong>Use Namespace Imports for large modules</strong>: For modules like <code>std.math</code>, importing as a namespace (<code>math.sqrt</code>) improves readability.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/stdlib">Standard Library</a> - Available modules</li><li><a href="/docs/guide/ffi">FFI</a> - Importing C functions</li><li><a href="/docs/guide/basics/first-project">Project Configuration</a> - Setting up <code>vex.json</code></li></ul>`,26)])])}const m=s(o,[["render",p]]);export{h as __pageData,m as default};
